#include<bits/stdc++.h>
using namespace std;
char s[1000010];
int or1[1000010],and1[1000010],or2[1000010],and2[1000010];
int n;
int ans1,ans2;
int dfs(int l,int r,int c=0)
{
    if(or2[r]>=l)
    {
        int temp=dfs(l,or2[r]-1);
        if(temp==1)
        {
            ans2++;
            return 1;
        }
        return dfs(or2[r]+1,r);
    }
    else if(and2[r]>=l)
    {
        int temp=dfs(l,and2[r]-1);
        if(temp==0)
        {
            ans1++;
            return 0;
        }
        return dfs(and2[r]+1,r);
    }
    if(s[l]=='('&&s[r]==')')
    {
        return dfs(l+1,r-1);
    }
    return s[l]-'0';
}
int main()
{  
    scanf("%s",s+1);
    n=strlen(s+1);
    int cnt=0;
    for(int i=1;i<=n;i++)
    {
        if(s[i]=='(')
        {
            cnt++;
        }
        if(s[i]==')')
        {
            cnt--;
        }
        if(s[i]=='&')
        {
            and1[cnt]=i;
        }
        if(s[i]=='|')
        {
            or1[cnt]=i;
        }
        and2[i]=and1[cnt];
        or2[i]=or1[cnt];
    }
    printf("%d\n",dfs(1,n));
    printf("%d %d",ans1,ans2);
	return 0;
}
